// Pre-register all marker layers so toggles appear immediately,
// even before any real markers arrive. Sending a deleted placeholder
// creates the layer group in the control panel without leaving a marker.
var layerSeeds = [
    "TAK Friendly", "TAK Hostile", "TAK Suspect", "TAK Neutral",
    "TAK Unknown", "TAK Other", "Meshtastic"
];
var seedMsgs = layerSeeds.map(function(layerName) {
    return {
        payload: {
            name: "_seed_" + layerName,
            layer: layerName,
            deleted: true
        }
    };
});

var msgs = [
    { payload: { command: { toptitle: 'CrypTAK WebMap' } } },
    { payload: { command: { toplogo: '/cryptak-logo.png' } } },
    { payload: { command: { coords: 'mgrs' } } },
    { payload: { command: { legend: legendHtml } } }
];
return [msgs.concat(seedMsgs)];

var p = msg.payload;
if (!p || p.action !== 'draw') return null;

var now   = new Date().toISOString();
var stale = new Date(Date.now() + 24 * 3600000).toISOString();

var uid  = 'NR-DRAW-' + p.name.replace(/\s+/g, '-');
var name = p.name || 'Drawing';

// CSS hex → signed 32-bit ARGB integer (TAK color format)
function cssToArgb(css, alpha) {
    alpha = (alpha !== undefined) ? alpha : 0xFF;
    var hex = (css || '#FFFFFF').replace('#', '');
    if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
    var r = parseInt(hex.substring(0, 2), 16) || 0;
    var g = parseInt(hex.substring(2, 4), 16) || 0;
    var b = parseInt(hex.substring(4, 6), 16) || 0;
    return ((alpha << 24) | (r << 16) | (g << 8) | b) | 0;
}

var opts = p.options || {};
var strokeColor = cssToArgb(opts.color || '#FFFF00');
var fillAlpha   = Math.round((opts.fillOpacity !== undefined ? opts.fillOpacity : 0.2) * 255);
var fillColor   = cssToArgb(opts.fillColor || opts.color || '#FFFF00', fillAlpha);
var weight      = opts.weight || 3.0;

function latlngsToLinks(arr) {
    return arr.map(function(pt) {
        return "<link point='" + pt.lat + "," + pt.lng + "'/>";
    }).join('');
}

function centroid(arr) {
    var lat = 0, lon = 0;
    arr.forEach(function(pt) { lat += pt.lat; lon += pt.lng; });
    return { lat: lat / arr.length, lon: lon / arr.length };
}

function eventWrap(type, centerLat, centerLon, detail) {
    return "<?xml version='1.0' encoding='UTF-8' standalone='yes'?>"
        + "<event version='2.0' uid='" + uid + "' type='" + type + "'"
        + " time='" + now + "' start='" + now + "' stale='" + stale + "' how='h-e'>"
        + "<point lat='" + centerLat + "' lon='" + centerLon + "'"
        + " hae='9999999.0' ce='9999999.0' le='9999999.0'/>"
        + "<detail>" + detail
        + "<strokeColor value='" + strokeColor + "'/>"
        + "<strokeWeight value='" + weight + "'/>"
        + "<fillColor value='" + fillColor + "'/>"
        + "<contact callsign='" + name + "'/>"
        + "<remarks>Drawn on CrypTAK WebMap</remarks>"
        + "<archive/><labels_on value='true'/>"
        + "</detail></event>";
}

var xml;

if (p.type === 'circlemarker' && p.lat && p.lon && p.radius) {
    xml = eventWrap('u-d-c-c', p.lat, p.lon,
        "<shape><ellipse major='" + p.radius + "' minor='" + p.radius + "' angle='360'/></shape>");

} else if (p.type === 'rectangle' && p.area) {
    var c = centroid(p.area);
    xml = eventWrap('u-d-r', c.lat, c.lon, latlngsToLinks(p.area));

} else if (p.type === 'polygon' && p.area) {
    var c = centroid(p.area);
    var links = latlngsToLinks(p.area);
    links += "<link point='" + p.area[0].lat + "," + p.area[0].lng + "'/>";
    xml = eventWrap('u-d-f', c.lat, c.lon, links);

} else if ((p.type === 'polyline' || p.type === 'route') && p.line) {
    var arr = p.line;
    if (Array.isArray(arr[0]) && arr[0].lat === undefined) arr = arr[0];
    var c = centroid(arr);
    xml = eventWrap('u-d-f', c.lat, c.lon, latlngsToLinks(arr));

} else {
    return null;
}

node.log('Draw→CoT: ' + p.type + ' "' + name + '" (' + xml.length + ' bytes)');
msg.payload = xml;
return msg;

var takCache = flow.get('takMarkers') || {};
var keys = Object.keys(takCache);
var clients = [];
var now = Date.now();

for (var i = 0; i < keys.length; i++) {
    var m = takCache[keys[i]];
    if (!m || !m.lat || !m.lon) continue;
    if (m._ageBased) continue;
    if (m._staleMs && m._staleMs < now) continue;
    clients.push({
        callsign: m.name || keys[i],
        lat: m.lat,
        lon: m.lon,
        team: (m.layer || '').replace('TAK ', '')
    });
}

msg.payload = { clients: clients, updated: now };
msg.headers = { 'Content-Type': 'application/json' };
return msg;
